#include<bits/stdc++.h>
using namespace std;

int dx[8] = {1, 0, -1, 0, 1, 1, -1, -1};
int dy[8] = {0, 1, 0, -1, -1, 1, -1, 1};
int ans;
char a[111][111];
int n, m;
void dfs(int x, int y) {
	a[x][y] = '.';
	for (int i = 0; i < 8; i++) {
		int mx = dx[i] + x;
		int my = dy[i] + y;
		if (a[mx][my] == 'W') {
			dfs(mx, my);
		}
	}
    return;
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			cin>>a[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			if(a[i][j]=='W'){
				dfs(i,j);
				ans++;
			}
		}
	}
	cout<<ans;
}
